resolved_rows as (
  select
    sites.id as site_id,
    source_rows.summary_date::date,
    source_rows.source,
    source_rows.source_file,
    source_rows.production_m3,
    source_rows.power_kwh,
    source_rows.chlorine_kg,
    source_rows.avg_flowrate_m3hr,
    source_rows.avg_pressure_psi,
    source_rows.avg_rc_ppm,
    source_rows.avg_turbidity_ntu,
    source_rows.avg_ph,
    source_rows.avg_tds_ppm,
    source_rows.peroxide_liters,
    source_rows.operating_hours,
    source_rows.scheduled_downtime_hours,
    source_rows.unscheduled_downtime_hours,
    source_rows.avg_upstream_pressure_psi,
    source_rows.avg_downstream_pressure_psi,
    source_rows.avg_vfd_frequency_hz,
    source_rows.avg_voltage_l1_v,
    source_rows.avg_voltage_l2_v,
    source_rows.avg_voltage_l3_v,
    source_rows.avg_amperage_a
  from source_rows
  join public.sites as sites
    on sites.name = source_rows.site_name
   and sites.type = source_rows.site_type
)
insert into public.daily_site_summaries (site_id, summary_date, source, source_file, production_m3, power_kwh, chlorine_kg, avg_flowrate_m3hr, avg_pressure_psi, avg_rc_ppm, avg_turbidity_ntu, avg_ph, avg_tds_ppm, peroxide_liters, operating_hours, scheduled_downtime_hours, unscheduled_downtime_hours, avg_upstream_pressure_psi, avg_downstream_pressure_psi, avg_vfd_frequency_hz, avg_voltage_l1_v, avg_voltage_l2_v, avg_voltage_l3_v, avg_amperage_a)
select site_id, summary_date, source, source_file, production_m3, power_kwh, chlorine_kg, avg_flowrate_m3hr, avg_pressure_psi, avg_rc_ppm, avg_turbidity_ntu, avg_ph, avg_tds_ppm, peroxide_liters, operating_hours, scheduled_downtime_hours, unscheduled_downtime_hours, avg_upstream_pressure_psi, avg_downstream_pressure_psi, avg_vfd_frequency_hz, avg_voltage_l1_v, avg_voltage_l2_v, avg_voltage_l3_v, avg_amperage_a
from resolved_rows
on conflict (site_id, summary_date) do update
set
  source = excluded.source,
  source_file = excluded.source_file,
  production_m3 = excluded.production_m3,
  power_kwh = excluded.power_kwh,
  chlorine_kg = excluded.chlorine_kg,
  avg_flowrate_m3hr = excluded.avg_flowrate_m3hr,
  avg_pressure_psi = excluded.avg_pressure_psi,
  avg_rc_ppm = excluded.avg_rc_ppm,
  avg_turbidity_ntu = excluded.avg_turbidity_ntu,
  avg_ph = excluded.avg_ph,
  avg_tds_ppm = excluded.avg_tds_ppm,
  peroxide_liters = excluded.peroxide_liters,
  operating_hours = excluded.operating_hours,
  scheduled_downtime_hours = excluded.scheduled_downtime_hours,
  unscheduled_downtime_hours = excluded.unscheduled_downtime_hours,
  avg_upstream_pressure_psi = excluded.avg_upstream_pressure_psi,
  avg_downstream_pressure_psi = excluded.avg_downstream_pressure_psi,
  avg_vfd_frequency_hz = excluded.avg_vfd_frequency_hz,
  avg_voltage_l1_v = excluded.avg_voltage_l1_v,
  avg_voltage_l2_v = excluded.avg_voltage_l2_v,
  avg_voltage_l3_v = excluded.avg_voltage_l3_v,
  avg_amperage_a = excluded.avg_amperage_a,
  updated_at = timezone('utc', now());
